/* Lucide Offline Fallback Script */
window.lucide = {
    createIcons: function() {
        // Encontra todas as tags com data-lucide
        const elements = document.querySelectorAll('[data-lucide]');
        elements.forEach(el => {
            const iconName = el.getAttribute('data-lucide');
            // Substitui de forma elegante o ícone por um caractere unicode se for offline
            const unicodeIcons = {
                'monitor': '🖥️',
                'shopping-cart': '🛒',
                'shopping-bag': '🛍️',
                'scan-line': '🔍',
                'keyboard': '⌨️',
                'check-circle': '✅',
                'alert-triangle': '⚠️',
                'scale': '⚖️',
                'check-square': '☑️',
                'banknote': '💵',
                'credit-card': '💳',
                'users': '👥',
                'alert-circle': 'ℹ️',
                'shield-check': '🛡️',
                'info': 'ℹ️',
                'settings': '⚙️',
                'refresh-cw': '🔄',
                'trash-2': '🗑️',
                'lock': '🔒',
                'user': '👤'
            };
            if (unicodeIcons[iconName]) {
                el.innerHTML = unicodeIcons[iconName];
                el.style.fontStyle = 'normal';
                el.style.marginRight = '4px';
            }
        });
    }
};
